// Multiformat Content Generator
// Processes video content and generates platform-specific content

const videoData = $input.first();

// Validate input data
if (!videoData.videoId || !videoData.brand || !videoData.title) {
  throw new Error('Invalid video data received');
}

// Brand-specific content strategies
const brandStrategies = {
  dax_traveler: {
    platforms: ['instagram', 'facebook', 'twitter', 'linkedin', 'tiktok', 'blog'],
    tone: 'personal, adventurous, inspiring',
    hashtags: ['#DaxTheTraveler', '#TravelAdventure', '#Wanderlust', '#TravelVlog'],
    cta: 'Join the Traveler\'s Club on Patreon for exclusive content!',
    affiliateOpportunities: ['travel gear', 'booking platforms', 'travel insurance']
  },
  timezone_travelers: {
    platforms: ['instagram', 'facebook', 'twitter', 'pinterest', 'blog'],
    tone: 'informative, helpful, professional',
    hashtags: ['#TimezoneTravel', '#TravelTips', '#TravelGuide', '#TravelHacks'],
    cta: 'Get our complete travel guides and itineraries!',
    affiliateOpportunities: ['travel guides', 'booking platforms', 'travel apps']
  },
  gods_vessel: {
    platforms: ['instagram', 'facebook', 'twitter', 'pinterest', 'blog'],
    tone: 'inspirational, faithful, encouraging',
    hashtags: ['#GodsVessel', '#Faith', '#ChristianLife', '#Inspiration'],
    cta: 'Shop faith-inspired apparel at God\'s Vessel!',
    affiliateOpportunities: ['christian books', 'devotionals', 'faith merchandise']
  },
  ani_dax: {
    platforms: ['instagram', 'facebook', 'twitter', 'tiktok', 'reddit'],
    tone: 'enthusiastic, knowledgeable, community-focused',
    hashtags: ['#AniDax', '#Anime', '#Manga', '#AnimeReview', '#Otaku'],
    cta: 'Join our anime community for reviews and recommendations!',
    affiliateOpportunities: ['anime merchandise', 'manga', 'streaming services']
  }
};

const strategy = brandStrategies[videoData.brand];
if (!strategy) {
  throw new Error(`Unknown brand: ${videoData.brand}`);
}

// Prepare content generation data
const contentData = {
  ...videoData,
  strategy,
  generationTimestamp: new Date().toISOString(),
  contentId: `${videoData.brand}_${videoData.videoId}_${Date.now()}`
};

return contentData;

// Generate platform-specific content using AI
const contentData = $('Prepare Content Data').first();
const currentPlatform = contentData.strategy.platforms[$('Process Each Platform').itemIndex];

if (!currentPlatform) {
  return null;
}

// Platform-specific content requirements
const platformSpecs = {
  instagram: {
    maxLength: 2200,
    format: 'visual-first',
    hashtagLimit: 30,
    includeEmojis: true,
    callToAction: true
  },
  facebook: {
    maxLength: 63206,
    format: 'engaging-story',
    hashtagLimit: 5,
    includeEmojis: true,
    callToAction: true
  },
  twitter: {
    maxLength: 280,
    format: 'concise-thread',
    hashtagLimit: 3,
    includeEmojis: true,
    callToAction: false
  },
  linkedin: {
    maxLength: 3000,
    format: 'professional',
    hashtagLimit: 5,
    includeEmojis: false,
    callToAction: true
  },
  tiktok: {
    maxLength: 2200,
    format: 'trendy-engaging',
    hashtagLimit: 10,
    includeEmojis: true,
    callToAction: true
  },
  pinterest: {
    maxLength: 500,
    format: 'descriptive-seo',
    hashtagLimit: 20,
    includeEmojis: false,
    callToAction: true
  },
  reddit: {
    maxLength: 40000,
    format: 'community-discussion',
    hashtagLimit: 0,
    includeEmojis: false,
    callToAction: false
  },
  blog: {
    maxLength: 10000,
    format: 'comprehensive-article',
    hashtagLimit: 10,
    includeEmojis: false,
    callToAction: true
  }
};

const spec = platformSpecs[currentPlatform];

// Create AI prompt for content generation
function createContentPrompt(videoData, platform, spec, strategy) {
  const basePrompt = `Generate ${platform} content based on this YouTube video:

Title: ${videoData.title}
Brand: ${videoData.brand}
Keywords: ${videoData.keywords.join(', ')}
Topics: ${videoData.topics.join(', ')}
Transcript excerpt: ${videoData.transcript.substring(0, 500)}...

Brand Strategy:
- Tone: ${strategy.tone}
- Target hashtags: ${strategy.hashtags.join(', ')}
- Call to action: ${strategy.cta}

Platform Requirements:
- Max length: ${spec.maxLength} characters
- Format: ${spec.format}
- Hashtag limit: ${spec.hashtagLimit}
- Include emojis: ${spec.includeEmojis}
- Include CTA: ${spec.callToAction}

`;

  const platformInstructions = {
    instagram: 'Create an engaging Instagram post with visual storytelling. Include relevant emojis and hashtags. Focus on the visual aspect and encourage engagement.',
    facebook: 'Write a compelling Facebook post that tells a story and encourages discussion. Use a conversational tone and include a clear call to action.',
    twitter: 'Create a Twitter thread (if needed) that captures the key points concisely. Use trending hashtags and encourage retweets.',
    linkedin: 'Write a professional LinkedIn post that provides value and insights. Focus on lessons learned and professional development aspects.',
    tiktok: 'Create TikTok caption that\'s trendy and engaging. Include popular hashtags and encourage user interaction.',
    pinterest: 'Write a Pinterest description that\'s SEO-optimized and descriptive. Focus on searchable keywords and visual appeal.',
    reddit: 'Create a Reddit post that encourages community discussion. Be authentic and provide value to the community.',
    blog: 'Write a comprehensive blog post outline with introduction, main points, and conclusion. Include SEO keywords and internal linking opportunities.'
  };

  return basePrompt + platformInstructions[platform] + '\n\nGenerate only the content, no explanations or meta-commentary.';
}

const prompt = createContentPrompt(contentData, currentPlatform, spec, contentData.strategy);

return {
  platform: currentPlatform,
  prompt,
  spec,
  contentData,
  aiModel: 'gpt-4o-mini' // Use cost-effective model for content generation
};

