// Process AI response and format content
const aiResponse = $input.first();
const platformData = $('Generate Platform Prompt').first();

if (!aiResponse.choices || !aiResponse.choices[0]) {
  throw new Error('Invalid AI response received');
}

const generatedContent = aiResponse.choices[0].message.content.trim();

// Extract hashtags from content
function extractHashtags(content) {
  const hashtagRegex = /#[a-zA-Z0-9_]+/g;
  return content.match(hashtagRegex) || [];
}

// Add affiliate links based on content and brand
function addAffiliateLinks(content, brand, topics) {
  const affiliateLinks = {
    dax_traveler: {
      'travel gear': 'https://amzn.to/travel-gear',
      'booking': 'https://booking.com/ref/dax-traveler',
      'insurance': 'https://worldnomads.com/ref/dax'
    },
    timezone_travelers: {
      'guides': 'https://amzn.to/travel-guides',
      'apps': 'https://apps.com/ref/timezone',
      'booking': 'https://booking.com/ref/timezone'
    },
    gods_vessel: {
      'books': 'https://amzn.to/christian-books',
      'merchandise': 'https://godsvesselstore.com',
      'devotionals': 'https://amzn.to/devotionals'
    },
    ani_dax: {
      'merchandise': 'https://amzn.to/anime-merch',
      'manga': 'https://amzn.to/manga-collection',
      'streaming': 'https://crunchyroll.com/ref/anidax'
    }
  };

  let contentWithLinks = content;
  const brandLinks = affiliateLinks[brand] || {};

  // Add relevant affiliate links based on topics
  Object.keys(brandLinks).forEach(keyword => {
    if (topics.some(topic => topic.toLowerCase().includes(keyword)) || 
        content.toLowerCase().includes(keyword)) {
      contentWithLinks += `\n\n🔗 ${brandLinks[keyword]}`;
    }
  });

  return contentWithLinks;
}

// Format final content
const hashtags = extractHashtags(generatedContent);
const contentWithAffiliates = addAffiliateLinks(
  generatedContent, 
  platformData.contentData.brand, 
  platformData.contentData.topics
);

// Create final content object
const finalContent = {
  platform: platformData.platform,
  content: contentWithAffiliates,
  hashtags,
  characterCount: contentWithAffiliates.length,
  brand: platformData.contentData.brand,
  videoId: platformData.contentData.videoId,
  contentId: platformData.contentData.contentId,
  generatedAt: new Date().toISOString(),
  status: 'generated',
  readyForPublishing: contentWithAffiliates.length <= platformData.spec.maxLength
};

return finalContent;

